        );

        // 2. Defensive Coding (NoClasspath Compatibility)
        // Ensure the tool runs even if library dependencies are missing
        launcher.getEnvironment().setNoClasspath(true);

        // ========================================================================

        launcher.addProcessor(new MigrationProcessor());

        try {
